3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	};
69	
70	const itemPremiumWithFirstInsurance = (item: Item): number => {
71	  const base = ITEM_BASE_PREMIUMS[item.type] ?? 0;
72	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
73	};
74	
75	const COMPONENT_TYPES = new Set(["rune"]);
76	const BLOCK_SIZE = 3;
77	const BLOCK_BASE = 60;
78	
79	const componentGroupBase = (count: number, unitBase: number): number => {
80	  if (count === BLOCK_SIZE) return BLOCK_BASE;
81	  return count * unitBase;
82	};
83	
84	const quotePremium = (items: Item[]): number => {
85	  let policyTotal = 0;
86	  const componentCounts = new Map<string, number>();
87	
88	  for (const item of items) {
89	    if (COMPONENT_TYPES.has(item.type)) {
90	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
91	    } else {
92	      policyTotal += itemPremiumWithFirstInsurance(item);
93	    }
94	  }
95	
96	  for (const [type, count] of componentCounts) {
97	    const unitBase = ITEM_BASE_PREMIUMS[type] ?? 0;
98	    const groupBase = componentGroupBase(count, unitBase);
99	    policyTotal += groupBase + groupBase * FIRST_INSURANCE_SURCHARGE_RATE;
100	  }
101	
102	  return roundUp(policyTotal) + PROCESSING_FEE;
103	};
104	
105	export const processScenario = (scenario: Scenario): ScenarioResult => {
106	  const results: StepResult[] = scenario.steps.map((step) => {
107	    if (step.op === "quote") {
108	      return { premium: quotePremium(step.items) };
109	    }
110	    return { payout: 0, remainingCap: 0 };
111	  });
112	  return { results };
113	};
